def build_template() -> Document:
    """Return a clean Document with all frames defined.

    Emitted by tools/idml_to_dsl.py from the source IDML; hand-edit as needed.
    """
    doc = Document(
        brand=Brand.gruene_noe(),
        title='26-03-leporello-z-falz-99x210-6-seitig-portrait',
        template_id='26-03-leporello-z-falz-99x210-6-seitig-portrait',
        author="Die Grünen Niederösterreich",
        facing_pages=False,
        layers=[
            DocumentLayer(name='Gestaltung'),
            DocumentLayer(name='Info', printable=False, editable=False),
        ],
        extra_doc_attrs={
            'DPIn':  'ISO Coated v2 300% (basICColor)',
            'DPIn2': 'ISO Coated v2 300% (basICColor)',
        },
        extra_pdf_attrs={
            'cropMarks': '0',
            'bleedMarks': '0',
        },
    )

    doc.add_color('Endformat', cmyk=(0, 100, 100, 0))
    doc.add_color('Faltung', cmyk=(50, 0, 100, 0))
    doc.add_color('Sicherheit', cmyk=(100, 0, 0, 0))

    # add_styles(doc) - paragraph styles (Phase G, task 5)
    _add_styles(doc)

    doc.add_master(
        name="Normal",
        size=(297, 210),
        bleed_mm=0,
        margins_mm=(0.0, 0.0, 0.0, 0.0),
    )

    page0 = doc.add_page(
        size=(297, 210),
        bleed_mm=0,
        margins_mm=(0.0, 0.0, 0.0, 0.0),
        master="Normal",
    )
    page1 = doc.add_page(
        size=(297, 210),
        bleed_mm=0,
        margins_mm=(0.0, 0.0, 0.0, 0.0),
        master="Normal",
    )

    _add_page_0(doc, page0)
    _add_page_1(doc, page1)

    return doc


